import { useState, useEffect } from 'react';

const API_KEY = 'sk-live-AbCdEf1234567890';

export default function App() {
  const [users, setUsers] = useState([]);
  useEffect(() => {
    fetch('/api/users?key=' + API_KEY)
      .then(r => r.json())
      .then(setUsers);
  }, []);
  return (
    <ul>
      {users.map(u => <li key={u.id}>{u.name}</li>)}
    </ul>
  );
}
